  if (key !== setupKey) return c.text('Access denied', 403);

  // 既にパスワード設定済みの場合は使用不可
  const admin = await c.env.DB.prepare(
    'SELECT password FROM admins WHERE username = ?'
  ).bind('admin').first<{ password: string }>();
